var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"MEMBER_HARMONY_PAST_NULL","text":{"KOREA":"으윽… 으으… 아, 아무것도 들리지 않아.","JPN":"ううっ……うう……な、何も聞こえない。","ENG":"Ugh... Gah... I-I can't hear anything.","TWN":"唉……唉……啊，我什麼也聽不見。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BOMB_DAMAGE_DOWN"},{"id":"L7_1","type":"dialog","speaker":"MEMBER_HARMONY_PAST_NULL","text":{"KOREA":"귀… 내 귀가… 아아…","JPN":"耳……私の耳が……ああ……","ENG":"My... My ears... Ahhh...","TWN":"我的…….我的耳朵……啊……"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm.","TWN":"嗯。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"단원들의 비명소리가 들리기에 와보았더니…","JPN":"団員たちの悲鳴が聞こえたので来てみれば……","ENG":"I heard the members screaming, so I made my way here...","TWN":"我聽到團員的慘叫聲，就趕了過來……"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신이 이들을 이런 꼴로 만든 건가요?","JPN":"あなたが彼らをこのような姿に？","ENG":"Are you the one responsible for this?","TWN":"是你把她們弄成這樣的？"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"예하께서… 말씀하셨어요.","JPN":"猊下が……おっしゃっていました。","ENG":"Her Eminence... told me.","TWN":"主教曾說過……"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"엘리시움 필하모닉은… 연주를 통해 세상 모든 것을 조율하려 한다고.","JPN":"エリシウムフィルハーモニーは……演奏を通じて世界のすべてを調律しようとしていると。","ENG":"The Elysium Philharmonic... tries to tune everything in this world through their performance.","TWN":"愛樂組織……是透過演奏來調和世界。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그러니… 아무것도 듣지 못한다면, 당신들은 더 이상 아무것도 연주할 수 없겠죠.","JPN":"だから……聴力を失えば、あなたたちはもう演奏できないでしょう。","ENG":"So... if you can't hear anything, you won't be able to play any instruments.","TWN":"所以……如果你聽不到任何聲音，你就不能再繼續演奏了。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"우리의 조율은 세계의 종말을 막기 위한 수단입니다.","JPN":"私たちの調律は、世界の終末を止めるための手段です。","ENG":"Our tuning is our way to stop the apocalypse.","TWN":"我們的調和是阻止世界末日的手段。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그래서… 사람들을 멋대로 희생시킨 건가요?","JPN":"だから……勝手に人々を犠牲にしたんですか？","ENG":"Is that why... you sacrificed people against their will?","TWN":"所以你……任意地犧牲了別人？"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"세상을 구하려고… 제 언니를 그렇게 만든 건가요?","JPN":"世界を救うため……私のお姉さんをこんな姿にしたんですか？","ENG":"Did you do that to my sister too...? To save the world?","TWN":"為了拯救世界……對我姊姊做了那種事？"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"다음 악장을 위해 끊어진 현을 갈아야 하듯, 실험에도 항상 새로운 자원이 필요합니다.","JPN":"次の楽章のために切れた弦を取り替えるように、実験にも常に新しい資源が必要です。","ENG":"A broken string must be replaced for the next movement, much like how experiments require new resources.","TWN":"要展開下一個樂章，就必須先換掉斷掉的弦，實驗也是需要新的資源的。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하께서도 모든 사실을 알고 계시지만, 이를 묵인하고 계신 걸요.","JPN":"猊下はすべての事実を知りながらも、これを黙認なさっているのです。","ENG":"Her Eminence is aware of all of this, but she has done nothing to stop us.","TWN":"主教也知道這一切，但是她默許了。"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그런데 고작 당신 한 명이 세상을 구하려는 우리 숭고한 연구를 방해할 셈인가요?","JPN":"なのに、たかがあなた一人で世界を救おうとする私たちの崇高な研究を邪魔するつもりですか？","ENG":"So, are you going to interfere with our noble research to save the world, alone?","TWN":"而就憑你一個人想要妨礙我們為拯救世界而展開的崇高研究嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"세상을 구한다고요? 그런 게 저에게 무슨 의미가 있죠?","JPN":"世界を救う？　そんなこと、私に何の意味があるの？","ENG":"Save the world? That doesn't mean anything to me.","TWN":"拯救世界？這對我有什麼意義？"},"stage":{"bg":"LABORATORY_02","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>내 세상은… 이미 당신들에게 짓밟히고 없는데.</color>","JPN":"<color=#ff3636>私の世界は……すでにあなたたちに踏みにじられてなくなったのに。</color>","ENG":"<color=#ff3636>My whole world... has already been crushed by you people.</color>","TWN":"<color=#ff3636>我的世界……早已被你們踩在腳底下。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"허억…!","JPN":"はっ……！","ENG":"*Gasp...!*","TWN":"咳……！"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"또 그 기억이군.","JPN":"またあの記憶だ。","ENG":"It's that same memory again.","TWN":"又來了。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"잠들 때마다 더 선명해지는 것 같은 기분은… 착각이 아니겠지.","JPN":"眠る度にどんどん鮮明になっていくのは……勘違いじゃないだろうね。","ENG":"It's probably right to assume... that it's getting clearer every time I sleep.","TWN":"每次入睡時，感覺就更加明顯……這應該不是錯覺。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"오늘은 날씨가 참 춥네요. 느닷없이 눈도 내리고.","JPN":"今日はとても寒いですね。急に雪も降り始めましたし。","ENG":"It's pretty cold today. Plus, the unexpected snow.","TWN":"今天天氣很冷，還下著雪。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"수고했어, 중사.","JPN":"お疲れ、軍曹。","ENG":"Good work, Sergeant.","TWN":"辛苦你了，中士。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 늘어져라 편히 자는 동안 혼자 밖에서 일한 거야?","JPN":"私がぐっすり寝てる間に、一人外で働いてたのか？","ENG":"Did you work alone outside while I was sleeping like a log?","TWN":"在我睡覺的時候，你一個人在外面工作嗎？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"제가 나서는 걸 싫어하긴 하지만, 이런 상황에 가만히 틀어박혀만 있는 건 불안해서요.","JPN":"私は出しゃばるのは嫌いですが、こんな状況でじっと閉じこもっているのも不安なんですよ。","ENG":"I'm not a big fan of taking initiative, but I'd feel anxious if I were cooped up inside.","TWN":"我雖然不喜歡挺身而出，但在這種情況下我也無法安心窩在屋裡。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"처음 관리국이 했던 제안대로 도심지에 거처를 마련했으면 이렇게 매번 땔감을 챙기는 수고는 안 해도 됐을 텐데 말이야.","JPN":"最初に管理局の提案通り都心で暮らしていれば、毎回こうやって薪を探す苦労はしなくて済んだのにね。","ENG":"If we had listened to the Administration and got a place in the city, we wouldn't have had to get firewood every time.","TWN":"如果按照管理局最初建議的那樣住在市中心，就不用每次都這麼辛苦地去搬柴火了。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"샤레이드는 도시니까요. 번화가에서 살게 되면 사람들을 많이 마주칠 거고… 그만큼 보는 눈도 많아지겠죠.","JPN":"シャレードは都市ですから。繁華街に住むと、たくさんの人と出くわすことになりますし……その分、人の目も多くなるでしょう。","ENG":"Charade is a city. If we live somewhere downtown, we're bound to run into a lot of people... which means more people are watching.","TWN":"查雷德是一座城市，如果住在市中心，就不得不面對很多人的眼光。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"이렇게 해서라도 최대한 문명과 떨어져 지내는 편이 그로니아 정부의 추적을 피하기엔 안전해요.","JPN":"こうやって文明と離れて暮らした方が、グロニア政府からの追跡も避けられて安全です。","ENG":"Staying far away from civilization like this is the safer way to avoid the Gronia government.","TWN":"為了躲避格羅尼亞政府的追蹤，還是儘量遠離文明社會比較安全。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"한창 연애할 나이에 나 같은 죄인을 수발 드느라, 중사가 고생이 많네.","JPN":"普通なら恋をしてるような年頃なのに、私のような罪人の世話をして、軍曹は大変だね。","ENG":"It must be troublesome for you to attend to a criminal like me, especially when you should be out there dating and stuff.","TWN":"青春年華連個戀愛也沒時間談，卻要伺候我這個罪犯，中士真是辛苦。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 빨리 재판을 받아야 중사도 마음 놓고 편히 지낼 텐데.","JPN":"私が早く裁判を受けないと、軍曹も楽に休めないのに。","ENG":"The sooner I get my trial, the sooner you'll be able to relax.","TWN":"我應該儘快受審，中士才能安下心來吧。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"그런 소리 좀 하지 말라니까요.","JPN":"そんなこと言わないでくださいよ。","ENG":"Oh, come on. Don't say that.","TWN":"別這麼說。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"누가 들으면 딸한테 부담주기 싫은 할머니인 줄 알겠네.","JPN":"他の人が聞いたら、娘に迷惑をかけたくないお婆さんみたいですよ。","ENG":"You sound like a grandmother who doesn't want to be a burden to her daughter.","TWN":"別人聽到會認為你是一個不想給女兒增加負擔的老奶奶。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러게.","JPN":"どうだろうな。","ENG":"Yeah.","TWN":"也是。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇게 얘기 하니까, 갑자기 엄마 생각이 나네.","JPN":"こんな話をしていたら、急にお母さんのことを思い出した。","ENG":"That reminds me of Mom when you say it like that.","TWN":"你這麼一說，我突然想起了我媽媽。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"죄송해요. 평소엔 하지도 않던 농담하려다 제가 괜한 소릴…","JPN":"すみません。普段はこんな冗談言わないのに、私が変なこと言っちゃったせいで……","ENG":"I'm sorry. I was only joking, but I shouldn't have–","TWN":"對不起，看來我確實不擅長開玩笑……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"우리 착한 엄마… 분명 천국에 계실 테니까, 난 죽어도 못 만나겠지.","JPN":"優しいお母さん……きっと天国にいるだろうから、私は死んでも会えないだろうな。","ENG":"My sweet mother... She's definitely in heaven, so I guess I'll never see her, even in death.","TWN":"我善良的媽媽……現在在天堂，我可能再也見不到她了。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"또 또 우울해지는 소리 한다. 약이라도 챙겨드려요?","JPN":"またそんなことを。薬でも飲みます？","ENG":"Again with the depressing talk. Do you want some pills for that?","TWN":"又說這些傷心話。要不要給你拿點藥？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"난 괜찮아. 평범한 사람에게도 가끔은 감상에 젖고는 하잖아.","JPN":"私は大丈夫。普通の人だってたまには感傷に浸ることもあるだろう？","ENG":"I'm fine. Even ordinary people sometimes get emotional.","TWN":"沒關係，正常人有時也會多愁善感。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나도 내가 사람이기 때문에 느낄 수 있는 기쁨… 슬픔… 죄책감… 그런 것들을 다 느껴보고 싶을 때가 있거든.","JPN":"私も自分が人だからこそ感じることのできる嬉しさ……悲しさ……罪悪感……そんなものを感じたい時があるんだよ。","ENG":"There are times when I want to feel emotions that can be felt because I'm human... Things like happiness... sadness... and guilt.","TWN":"有時候我想感受那些我作為人類可以感受到所有感情，快樂……悲傷……罪惡感……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 정말 감정을 가지고 있는 사람인지, 확인해보고 싶은 걸지도 모르지.","JPN":"私が本当に感情を持っている人間なのか、確認したいのかもしれない。","ENG":"Maybe I want to check if I'm still a human with emotions.","TWN":"或許我是想確認自己是不是一個有情感的人。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"아직도… 레아 씨는 자신이 괴물이라고 생각하는 건가요?","JPN":"まだ……レアさんは自分が化け物だと思ってるんですか？","ENG":"Do you... still think you're a monster?","TWN":"蕾亞……依然覺得自己是一個怪物嗎？"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나는 나야. 중사.","JPN":"私は私だよ。軍曹。","ENG":"I'm just me, Sergeant.","TWN":"我就是我，中士。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"난 괴물 마에스트로이기도 하고, 엄마의 딸 레아이기도 해. 그 어느 것도 외면해서는 안 될 내 모습이야.","JPN":"私は化け物のマエストロであり、お母さんの娘レアでもある。どちらも目を背けてはいけない私の姿だ。","ENG":"I am the monster Maestra, and I am my mom's daughter, Leah. They're both aspects of myself I shouldn't ignore.","TWN":"我是怪物指揮家，也是媽媽的女兒蕾亞，這些都是我無法逃避的本相。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"갖고 싶은 기억만 가지고 살아간다면, 그건 그저 현실도피일 뿐이니까.","JPN":"きれいな記憶だけを持って生きていくのは、ただの現実逃避だからね。","ENG":"I'd be denying reality if I were to live exclusively with the memories I wanted to keep.","TWN":"因為如果只活在希望擁有的回憶裡，那只是在逃避現實。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"뭐가 됐든 상관없어요.","JPN":"どっちだって構いません。","ENG":"Whatever the case, it doesn't matter.","TWN":"是什麼並不重要。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"전 그저 당신이 그로니아가 아니라 공정한 곳에서 재판을 받고, 마땅한 죗값을 치르길 원할 뿐이에요.","JPN":"私はただ、あなたがグロニアではなくもっと公正なところで裁判を受けて、妥当な罰を受けてほしいだけです。","ENG":"I just want you to get a fair trial outside of Gronia and pay for your crimes.","TWN":"我只想讓你在格羅尼亞以外的地方公平地接受審判，並得到你應得的懲罰。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"응, 죗값을 치를 거야.","JPN":"うん、罰を受けるよ。","ENG":"Yes, I will pay for my crimes.","TWN":"嗯，我會的。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"중사가 날 위해 내린 선택… 절대로 후회하지 않게 할 테니까.","JPN":"軍曹が私のためにした選択を……絶対に後悔させない。","ENG":"I won't make you regret... the choices you made for me, Sergeant.","TWN":"我不會讓中士後悔……為我做出的選擇.。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨…","JPN":"レアさん……","ENG":"Leah...","TWN":"蕾亞……"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"진지할 때도 배가 고픈 걸 보니, 사람인 건 확실하네.","JPN":"真剣な話の途中でもお腹が空くのをみると、確かに私は人間のようだね。","ENG":"I guess I really am human, since I feel hungry in a situation like this.","TWN":"這麼認真的時刻也能感到饑餓，果然是人類。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"하하… 오늘은 제 차례죠? 밥 준비할게요.","JPN":"はは……今日は私の番ですよね？　ご飯の準備をします。","ENG":"Haha... It's my turn to cook today, right? I'll go prepare a meal.","TWN":"哈哈……今天輪到我了吧？ 我來準備吃的。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래. 난 잠깐 바람 좀 쐬다 올게.","JPN":"うん。私はちょっと風に当たってくる。","ENG":"Okay. I'm going to go get some fresh air.","TWN":"好，那我去透透氣。"},"stage":{"bg":"ROOM_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…흐음, 공기 좋네.","JPN":"……ふーん、いい空気だ。","ENG":"...Hmm. Refreshing.","TWN":"……嗯，空氣不錯。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그림자는 아닌 것 같은데…","JPN":"シャドウではなさそうだけど……","ENG":"I don't think you're a Shadow...","TWN":"好像不是暗影……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 아까부터 기분 나쁘게 남의 집 주변을 맴도는 거야?","JPN":"どうしてさっきから人の家の周りをうろついてるんだ？　気持ち悪い。","ENG":"But why have you been circling around our house? It's creepy, you know.","TWN":"為什麼在我家周圍徘徊？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"그림자의… 나약해진 냄새는… 우리를… 부르지.","JPN":"弱クナッタ……シャドウノ匂イハ……ワレワレヲ……呼ブ。","ENG":"Smell... of a weakened Shadow... calls... for us...","TWN":"暗影……微弱的氣息……會召喚……我們。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"사람 말을 하는 침식체라. 오래 살고 볼 일이네.","JPN":"人の言葉をしゃべる侵食体か。長生きしてみるものだね。","ENG":"A C.O. that can talk. What a rare sight.","TWN":"會說話的侵蝕體，真是罕見。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래서, 날 잡고 싶어서 온 거야?","JPN":"それで、私を捕まえに来たのか？","ENG":"So, are you here because you want to kill me?","TWN":"所以你是來抓我的？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"살아있는 걸 쫓아… 그것이 우리…","JPN":"生キテイルモノヲ追ウ……ソレガワレワレ……","ENG":"Chasing things that are alive... that is us...","TWN":"追逐活物……這就是我們……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"살아있는 <color=#ffd34c>가능성</color>… 우리가 갖는다.","JPN":"生キテイル<color=#ffd34c>可能性</color>……ワレワレガ手ニ入レル。","ENG":"Living <color=#ffd34c>possibilities</color>... we will take.","TWN":"生存的<color=#ffd34c>可能性</color>……我們要奪取。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래. 네 목적은 대강 알겠어.","JPN":"そう。君の目的は大体わかった。","ENG":"Right. I understand what your objective is.","TWN":"好吧，我知道你想幹什麼了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"말이 통하니 일단 물어는 보겠는데, 얌전히 돌아갈 생각은 없지?","JPN":"言葉が通じるようだから一応聞くけど、大人しく帰る気はないんだね？","ENG":"Since you can talk, I have to ask. You're not willing to turn around and go back, are you?","TWN":"既然你能說話，我就問你吧。你不會乖乖回去對嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"크. 크.","JPN":"ク。ク。","ENG":"Ke. Ke.","TWN":"咳咳。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"큭- 큭- 큭- 큭-","JPN":"ク。ク。ク。ク。","ENG":"Ke- ke- ke- ke-","TWN":"咳——咳——咳——咳——"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하, 기분 나쁠 정도로 유쾌한 자식이네.","JPN":"はっ、気持ち悪いくらい愉快なやつだな。","ENG":"Ha. What a disturbingly delightful guy.","TWN":"哈，好討厭。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};